SELECT DISTINCT ?player WHERE {
  ?player p:P54 ?stmt;
         ps:P54 wd:Q275328.
  ?stmt pq:P580 ?start.
  FILTER (YEAR(?start) <= 2022 && (NOT EXISTS { ?stmt pq:P582 ?end } || YEAR(?end) >= 2022))
  FILTER (?player != wd:Q2522057)
  ?player p:P54 ?careerStmt.
  ?careerStmt pq:P580 ?careerStart.
  FILTER (YEAR(?careerStart) <= 2011)
}

